#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long B, X;
        scanf("%lld %lld", &B, &X);
        long long count = 0;
        for (long long N = 1; N <= B / X; N++) {
            for (long long D = N + 1; D * D <= B; D++) {
                if ((N * X) % D == 0 && D > N) {
                    count++;
                    break;
                }
            }
        }
        printf("%lld\n", count);
    }
    return 0;
}

